ソースコード位置： <code>ttflow/ttflow.py</code> <pre><code>def setup(
    state_repository: str = "local:state.json",
) -&gt; Client:
    if state_repository.startswith("local:"):
        from .state_repository.local_file_state import LocalFileStateRepository

        s = LocalFileStateRepository(state_file=Path(state_repository[len("local:") :]))
    elif state_repository.startswith("dynamodb:"):
        from .state_repository.dynamodb import DynamoDBStateRepository

        s = DynamoDBStateRepository(
            table_name=state_repository[len("dynamodb:") :],
        )
    elif state_repository.startswith("s3:"):
        from .state_repository.s3 import S3StateRepository

        s3_path = state_repository[len("s3:") :]
        if "/" not in s3_path:
            bucket = s3_path
            prefix = ""
        else:
            bucket, prefix = s3_path.split("/", maxsplit=1)

        s = S3StateRepository(
            bucket_name=bucket,
            prefix=prefix,
        )
    elif state_repository.startswith("onmemory"):
        from .state_repository.on_memory_state import OnMemoryStateRepository

        s = OnMemoryStateRepository()
    else:
        raise UnknownRepositoryError(f"Unknown repository: {state_repository}")

    return Client(
        Global(
            state=BufferCacheStateRepositoryProxy(s),
        )
    )
</code></pre>

ソースコード位置： <code>ttflow/core/workflow.py</code> <pre><code>def workflow(g: Global, trigger: Trigger | str | None = None) -&gt; Callable:
    def _decorator(f: Callable) -&gt; Callable:
        if trigger is None:
            t = EventTrigger(f"_trigger_{f.__name__}")
        elif isinstance(trigger, str):
            t = EventTrigger(f"_trigger_{trigger}")
        else:
            t = trigger
        wf = Workflow(t, f)
        g.workflows.append(wf)

        @functools.wraps(f)
        def _wrapper(*args, **kwargs):
            raise WorkflowDirectCallError("workflow can not be called directly")

        return _wrapper

    return _decorator
</code></pre>

ソースコード位置： <code>ttflow/core/workflow.py</code> <pre><code>def sideeffect(g: Global) -&gt; Callable:
    def _decorator(f: Callable) -&gt; Callable:
        if inspect.iscoroutinefunction(f):
            # async sideeffect: syncワークフローからの呼び出しを検出するため、
            # 通常の関数でラップし、実行中イベントループの有無で判定する
            @functools.wraps(f)
            def _async_guard(*args, **kwargs):
                try:
                    asyncio.get_running_loop()
                except RuntimeError:
                    raise SideeffectUsageError(
                        "async sideeffectはasyncワークフローからのみ呼び出せます"
                    )
                return _async_impl(*args, **kwargs)

            async def _async_impl(*args, **kwargs):
                if len(args) == 0 or not isinstance(args[0], RunContext):
                    raise SideeffectUsageError(
                        "sideeffectはRunContextを第1引数に取る必要があります"
                    )
                c = args[0]

                @_execute_once_async(g, c.get_context_data())
                async def a():
                    return await f(*args, **kwargs)

                return await a()

            return _async_guard
        else:
            # sync sideeffect
            @functools.wraps(f)
            def _wrapper(*args, **kwargs):
                if len(args) == 0 or not isinstance(args[0], RunContext):
                    raise SideeffectUsageError(
                        "sideeffectはRunContextを第1引数に取る必要があります"
                    )
                c = args[0]

                @_execute_once(g, c.get_context_data())
                def a():
                    return f(*args, **kwargs)

                return a()

            return _wrapper

    return _decorator
</code></pre>

